+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\([!"#$%&'()*+,\\-./:;<=>?@[\\\\\\]^_`{|}~ ])/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string | null {
+  const headingIndex = target.indexOf('#');
+  if (headingIndex === -1) return null;
+  const page = target.substring(0, headingIndex);
+  const heading = target.substring(headingIndex + 1);
+  if (!heading) return null;
+  return page ? `${page} > ${heading}` : heading;
+}
+
+function convertWikiLinks(text: string, linkStyle: LinkStyleValue, imageStyle: LinkStyleValue): string {
+  return text.replace(/(!?)\\[\\[([^\
\\]]+)\\]\\]/g, (match, bang: string, contents: string) => {
+    const image = bang === '!';
+    if ((image ? imageStyle : linkStyle) !== 'markdown') return match;
+
+    const separator = contents.indexOf('|');
+    const target = separator === -1 ? contents : contents.substring(0, separator);
+    let display = separator === -1 ? '' : contents.substring(separator + 1);
+    if (!target) return match;
+
+    if (image) {
+      // Obsidian's width and width-by-height embed syntax has no Markdown equivalent.
+      if (/^\\d+(?:x\\d+)?$/.test(display)) display = '';
+      return `![${display || target}](${target})`;
+    }
+
+    return `[${display || defaultHeadingDisplay(target) || target}](${target})`;
+  });
+}
