import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';

type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';

class LinkStyleOptions implements Options {
  linkStyle: LinkStyleValue = 'no-change';
  imageStyle: LinkStyleValue = 'no-change';
}

type MarkdownLink = {end: number, image: boolean, label: string, target: string};

function unescapeMarkdown(value: string): string {
  return value.replace(/\\([!"#$%&'()*+,\-./:;<=>?@[\\\]^_`{|}~ ])/g, '$1');
}

function defaultHeadingDisplay(target: string): string | null {
  const headingIndex = target.indexOf('#');
  if (headingIndex === -1) return null;
  const page = target.substring(0, headingIndex);
  const heading = target.substring(headingIndex + 1);
  if (!heading) return null;
  return page ? `${page} > ${heading}` : heading;
}

function hasUnescapedWhitespace(value: string): boolean {
  for (let i = 0; i < value.length; i++) {
    if (value[i] === '\\') {
      i++;
    } else if (value[i] === ' ' || value[i] === '\t') {
      return true;
    }
  }
  return false;
}

function convertWikiLinks(text: string, linkStyle: LinkStyleValue, imageStyle: LinkStyleValue): string {
  return text.replace(/(!?)\[\[([^\n\]]+)\]\]/g, (match, bang: string, contents: string) => {
    const image = bang === '!';
    if ((image ? imageStyle : linkStyle) !== 'markdown') return match;

    const separator = contents.indexOf('|');
    const target = separator === -1 ? contents : contents.substring(0, separator);
    let display = separator === -1 ? '' : contents.substring(separator + 1);
    if (!target) return match;

    if (image) {
      // Obsidian's width and width-by-height embed syntax has no Markdown equivalent.
      if (/^\d+(?:x\d+)?$/.test(display)) display = '';
      return `![${display || target}](${target})`;
    }

    return `[${display || defaultHeadingDisplay(target) || target}](${target})`;
  });
}

function parseMarkdownLink(text: string, bracketStart: number): MarkdownLink | null {
  const image = bracketStart > 0 && text[bracketStart - 1] === '!';
  let cursor = bracketStart + 1;
  let depth = 1;
  while (cursor < text.length && depth > 0) {
    if (text[cursor] === '\n' || text[cursor] === '\r') return null;
    if (text[cursor] === '\\') {
      cursor += 2;
      continue;
    }
    if (text[cursor] === '[') depth++;
    if (text[cursor] === ']') depth--;
    cursor++;
  }
  if (depth !== 0 || text[cursor] !== '(') return null;

  const label = text.substring(bracketStart + 1, cursor - 1);
  const destinationStart = ++cursor;
  let destination = '';
  if (text[cursor] === '<' || /[ \t]/.test(text[cursor] || '')) {
    while (/[ \t]/.test(text[cursor] || '')) cursor++;
    if (text[cursor] === '<') {
      const targetStart = ++cursor;
      while (cursor < text.length && text[cursor] !== '>') {
        if (text[cursor] === '\n' || text[cursor] === '\r') return null;
        if (text[cursor] === '\\') cursor++;
        cursor++;
      }
      if (text[cursor] !== '>') return null;
      destination = text.substring(targetStart, cursor++);
      while (/[ \t]/.test(text[cursor] || '')) cursor++;
      if (text[cursor] !== ')') return null; // a title, or otherwise non-inline syntax
      if (destination.includes('_PLACEHOLDER}')) return null;
      return {end: cursor + 1, image, label: unescapeMarkdown(label), target: unescapeMarkdown(destination)};
    }
    // Whitespace before a non-angle destination is not supported by this rule.
    return null;
  }

  let parentheses = 0;
  while (cursor < text.length) {
    const character = text[cursor];
    if (character === '\n' || character === '\r') return null;
    if (character === '\\') {
      cursor += 2;
      continue;
    }
    if (character === '(') parentheses++;
    if (character === ')') {
      if (parentheses === 0) break;
      parentheses--;
    }
    cursor++;
