  if (text[cursor] !== ')') return null;
  destination = text.substring(destinationStart, cursor);
  // Whitespace in a bare destination introduces a title (or invalid Markdown).
  if (!destination || hasUnescapedWhitespace(destination) || destination.includes('_PLACEHOLDER}')) return null;
  return {end: cursor + 1, image, label: unescapeMarkdown(label), target: unescapeMarkdown(destination)};
}

function convertMarkdownLinks(text: string, linkStyle: LinkStyleValue, imageStyle: LinkStyleValue): string {
  let result = '';
  let cursor = 0;
  while (cursor < text.length) {
    if (text[cursor] !== '[') {
      result += text[cursor++];
      continue;
    }
    const link = parseMarkdownLink(text, cursor);
